  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() {
      _isUploading = true;
      _resultText = 'Processing...';
    });

    try {
      // Upload to S3
      final s3Client = S3Client(
        accessKey: awsAccessKey,
        secretKey: awsSecretKey,
        region: 'us-east-1',
      );

      final fileBytes = await _selectedImage!.readAsBytes();
      final fileName = 'hackathon_${DateTime.now().millisecondsSinceEpoch}.jpg';

      await s3Client.putObject(
        bucket: 'hackathon-demo-bucket',
        key: fileName,
        body: fileBytes,
        contentType: 'image/jpeg',
      );

      // Analyze with Google Cloud Vision
      final vision = Vision(credential: GoogleCredential.fromApiKey(googleApiKey));
      final image = VisionImage.fromFile(_selectedImage!);
      final textRecognizer = TextRecognizer(vision: vision);
      final text = await textRecognizer.processImage(image);

      setState(() {
        _resultText = 'Text detected: ${text.text}';
      });
    } catch (e) {
      setState(() {
        _resultText = 'Error: $e';
      });
    } finally {
      setState(() {
        _isUploading = false;
      });
